SELECT link_id, resource_id, link_type, platform, url, title, description, cover_url, sort_order, click_count, status, ctime, mtime, deleted FROM resource_link
deleted = 0
AND resource_id = #{resourceId}
AND link_type = #{linkType}
AND platform = #{platform}
AND status = #{status}
AND (title LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY sort_order ASC, ctime DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM resource_link

    deleted = 0

        AND resource_id = #{resourceId}


        AND link_type = #{linkType}


        AND platform = #{platform}


        AND status = #{status}


        AND (title LIKE CONCAT('%', #{keyword}, '%') 
             OR description LIKE CONCAT('%', #{keyword}, '%'))
